  label: string;
  path: string;
}

export interface Memory {
  id: string;
  author: string;
  content: string;
  date: string;
  isAiRefined?: boolean;
}

// Keeping SectionId enum for legacy reference or internal anchor usage if needed, 
// though mostly replaced by routes now.
export enum SectionId {
  HERO = 'hero',
  BIO = 'bio',
  GALLERY = 'gallery',
  PROJECTS = 'projects',
  MEMORIES = 'memories',
  THANK_YOU = 'thank-you',
}

import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

export const ScrollToTop = () => {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

