import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X } from 'lucide-react';
import { NavItem } from '../types';

export const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();
  const isHomePage = location.pathname === '/';

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // On pages other than home, the navbar should always have a solid background
  const showSolidBackground = isScrolled || !isHomePage;

  const navLinks: NavItem[] = [
    { label: 'ראשי', path: '/' },
    { label: 'סיפור חייו', path: '/bio' },
    { label: 'פרויקטים', path: '/projects' },
    { label: 'תודות', path: '/thank-you' },
    { label: 'גלריה', path: '/gallery' },
    { label: 'זכרונות', path: '/memories' },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${showSolidBackground ? 'bg-white shadow-md py-2' : 'bg-transparent py-4'}`}>
      <div className="container mx-auto px-4 flex justify-between items-center">
        <Link to="/" className={`font-display font-bold text-xl ${showSolidBackground ? 'text-memorial-dark' : 'text-white'}`}>
          רונאל בן משה ז"ל
        </Link>

        {/* Desktop Menu */}
        <div className="hidden md:flex gap-8">
          {navLinks.map((link) => {
            const isActive = location.pathname === link.path;
            return (
              <Link
                key={link.label}
                to={link.path}
                className={`font-medium text-sm transition-colors duration-300 hover:text-memorial-gold 
                  ${isActive ? 'text-memorial-gold font-bold' : (showSolidBackground ? 'text-gray-600' : 'text-gray-200')}
                `}
              >
                {link.label}
              </Link>
            );
          })}
        </div>

        {/* Mobile Menu Button */}
        <button 
          className="md:hidden"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? (
            <X className={showSolidBackground ? 'text-black' : 'text-white'} />
          ) : (
            <Menu className={showSolidBackground ? 'text-black' : 'text-white'} />
          )}
        </button>
      </div>

      {/* Mobile Menu Dropdown */}
      {isMobileMenuOpen && (
        <div className="absolute top-full left-0 right-0 bg-white shadow-lg md:hidden p-4 flex flex-col gap-4 border-t">
          {navLinks.map((link) => (
            <Link
              key={link.label}
              to={link.path}
              className={`text-lg py-2 border-b border-gray-100 last:border-0 ${location.pathname === link.path ? 'text-memorial-gold font-bold' : 'text-gray-800'}`}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              {link.label}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
};

import React, { useState } from 'react';
import { Memory } from '../types';
import { refineMemoryText } from '../services/geminiService';
import { Send, Sparkles, Loader2 } from 'lucide-react';

export const MemoryWall: React.FC = () => {
  const [memories, setMemories] = useState<Memory[]>([
    { id: '1', author: 'חבר מהצוות', content: 'רונאל היה הלב של הפלוגה. תמיד עם חיוך, תמיד ראשון לעזור. לא נתפס שאתה לא כאן.', date: '2023-11-01' },
    { id: '2', author: 'משפחת כהן', content: 'תודה על האור שהפצת בעולם. לא נשכח אותך לעולם.', date: '2023-12-15' },
  ]);
  const [newMemory, setNewMemory] = useState('');
  const [author, setAuthor] = useState('');
  const [isRefining, setIsRefining] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMemory.trim() || !author.trim()) return;

    setIsRefining(true);

    // Use Gemini to check/refine the text (Simulating a server-side process here)
    const refinedText = await refineMemoryText(newMemory);

    const memory: Memory = {
      id: Date.now().toString(),
      author: author,
      content: refinedText,
      date: new Date().toISOString().split('T')[0],
      isAiRefined: refinedText !== newMemory
    };

    setMemories([memory, ...memories]);
    setNewMemory('');
    setAuthor('');
    setIsRefining(false);
  };

  return (
    <section className="min-h-screen pt-32 pb-24 bg-memorial-dark text-white">
      <div className="container mx-auto px-4 max-w-4xl">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-display font-bold text-memorial-gold mb-4">כותבים לרונאל</h2>
          <p className="text-gray-300">שתפו זכרון, מחשבה או מילות פרידה</p>
        </div>

        {/* Input Form */}
        <div className="bg-white/5 p-6 rounded-xl border border-white/10 mb-12">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label htmlFor="author" className="block text-sm font-medium text-gray-300 mb-1">שם מלא</label>
              <input
                type="text"
                id="author"
                value={author}
                onChange={(e) => setAuthor(e.target.value)}
                className="w-full bg-white/10 border border-white/20 rounded-lg p-3 text-white focus:outline-none focus:ring-2 focus:ring-memorial-gold"
                placeholder="השם שלך..."
                required
              />
            </div>
            <div>
              <label htmlFor="content" className="block text-sm font-medium text-gray-300 mb-1">הזכרון שלך</label>
              <textarea
                id="content"
                value={newMemory}
                onChange={(e) => setNewMemory(e.target.value)}
                rows={4}
                className="w-full bg-white/10 border border-white/20 rounded-lg p-3 text-white focus:outline-none focus:ring-2 focus:ring-memorial-gold"
                placeholder="כתבו כאן..."
                required
              />
            </div>
            <button
              type="submit"
              disabled={isRefining}
              className="w-full bg-memorial-gold hover:bg-yellow-600 text-white font-bold py-3 rounded-lg transition flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {isRefining ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  מעבד טקסט...
                </>
              ) : (
                <>
                  <Send size={20} />
                  שליחת זכרון
                </>
              )}
            </button>
            <div className="text-xs text-center text-gray-500 flex items-center justify-center gap-1 mt-2">
              <Sparkles size={12} />
              <span>הטקסט נבדק ועובר הגהה קלה באמצעות בינה מלאכותית לשמירה על כבוד המעמד</span>
            </div>
          </form>
        </div>

        {/* Memories List */}
        <div className="space-y-6">
          {memories.map((mem) => (
            <div key={mem.id} className="bg-white/10 p-6 rounded-lg backdrop-blur-sm border-r-4 border-memorial-gold">
              <p className="text-lg mb-4 leading-relaxed whitespace-pre-line">"{mem.content}"</p>
              <div className="flex justify-between items-center text-sm text-gray-400">
                <span className="font-bold text-gray-200">{mem.author}</span>
                <span>{mem.date}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};
